import { html, customElement, property, css, when } from '@umbraco-cms/backoffice/external/lit';
import type { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import type { UUIInputEvent } from '@umbraco-ui/uui-input';
import type { Field } from '@umbraco-forms/generated';
import type { UUISelectEvent } from '@umbraco-ui/uui';
import { FORMS_FORM_WORKSPACE_CONTEXT } from '../../section/forms/workspace/form-workspace.context-token.js';

const elementName = "forms-field-mapper-property-editor";

export type FieldMapping = { alias: string, value: string, staticValue: string }

@customElement(elementName)
export class FormsFieldMapperPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;

  #value: string = "";

  @property({ type: String })
  get value() { return this.#value; }
  set value(value: string) {
    const oldVal = this.#value;
    this.#value = value;
    this.requestUpdate('value', oldVal);

    this.#initializeMappings(value);
  }

  #mappings: Array<FieldMapping> = [];

  #fieldSelectOptions: Array<Option> = [];

  constructor() {
    super();

		this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
			this.#workspaceContext = instance;
      this.#initializeFieldSelectOptions();
		});
  }

  #initializeMappings(value?: string) {
    if (value && value.length > 0) {
      this.#mappings = JSON.parse(value);
    }
  }

  #initializeFieldSelectOptions() {
    const allFields = this.#workspaceContext!.getAllFields();
    const options = allFields.map((f: Field) => { return { name: f.caption, value: f.id }});
    options.unshift({name: "Map a field", value: ""})  // Can't use the uui-select placeholder here, as we want to be able to deselect.
    this.#fieldSelectOptions = options;
  }

  #getFieldSelectOptionsWithSelectedValue(value: string) {
    return this.#fieldSelectOptions.map((o: Option) => {
      return {
        ...o,
        selected: o.value === value ? true : undefined
      }
    });
  }

  #onAliasChange(e: UUIInputEvent, idx: number) {
    const value = e.target.value.toString();
    this.#mappings[idx].alias = value;
    this.#refreshValue();
  }

  #onFieldSelectChange(e: UUISelectEvent, idx: number) {
    const value = e.target.value.toString();
    this.#mappings[idx].value = value;
    this.#refreshValue();
  }

  #onStaticValueChange(e: UUIInputEvent, idx: number) {
    const value = e.target.value.toString();
    this.#mappings[idx].staticValue = value;
    this.#refreshValue();
  }

  #onDeleteClick(index: number) {
    this.#mappings.splice(index, 1);
    this.#refreshValue();
  }

  #onAddClick() {
    this.#mappings.push({ alias: "", value: "", staticValue: "" });
    this.#refreshValue();
  }

  #refreshValue() {
    this.value = JSON.stringify(this.#mappings);
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  async connectedCallback() {
    super.connectedCallback();
  }

    render() {
    return html`

      ${when(this.#mappings.length > 0,
        () => html`
          <div class="umb-forms-mappings">

            <div class="umb-forms-mapping-header">
                <div class="umb-forms-mapping-field -no-margin-left">Alias</div>
                <div class="umb-forms-mapping-field">Form value</div>
                <div class="umb-forms-mapping-field">Static value</div>
                <div class="umb-forms-mapping-remove -no-margin-right"></div>
            </div>

            ${this.#mappings.map((mapping, idx) => html`
              <div class="umb-forms-mapping">

                <div class="umb-forms-mapping-field -no-margin-left">
                  <uui-input
                    type="text"
                    label="Alias"
                    placeholder="Alias"
                    .value=${mapping.alias}
                    @change=${(e: UUIInputEvent) => this.#onAliasChange(e, idx)}
                  ></uui-input>
                </div>

                <div class="umb-forms-mapping-field">
                  <uui-select
                    .options=${this.#getFieldSelectOptionsWithSelectedValue(mapping.value)}
                    placeholder="Map a field"
                    @change=${(e: UUISelectEvent) => this.#onFieldSelectChange(e, idx)}>
                  </uui-select>
                </div>

                <div class="umb-forms-mapping-field">
                  <uui-input
                    type="text"
                    label="Static value"
                    placeholder="Static value"
                    .value=${mapping.staticValue}
                    @change=${(e: UUIInputEvent) => this.#onStaticValueChange(e, idx)}
                  ></uui-input>
                </div>

                <div class="umb-forms-mapping-remove -no-margin-right">
                  <uui-button
                    label=${this.localize.term("general_delete")}
                    look="secondary"
                    color="default"
                    @click=${() => this.#onDeleteClick(idx)}
                  >
                    <uui-icon name="icon-delete"></uui-icon>
                  </uui-button>
                </div>

              </div>
            `)}
          </div>`)}

          <uui-button
            label="add"
            look="secondary"
            color="default"
            @click=${this.#onAddClick}
          >
            <uui-icon name="icon-add"></uui-icon>
          </uui-button>
        `;
  }

  static styles = [
		css`
    .umb-forms-mappings {
      display: flex;
      flex-direction: column;
    }

    .umb-forms-mapping-header {
        display: flex;
        flex-direction: row;
        font-weight: bold;
    }

    .umb-forms-mapping {
        display: flex;
        flex-direction: row;
        margin-bottom: 5px;
        align-items: center;
    }

    .umb-forms-mapping-field {
        flex: 1 1 33%;
        margin: 5px;
    }

    .umb-forms-mapping-field input,
    .umb-forms-mapping-field select {
        margin-bottom: 0;
    }

    .umb-forms-mapping-field.-no-margin-left {
        margin-left: 0;
    }

    .umb-forms-mapping-remove {
        flex: 1 1 20px;
        margin: 5px;
    }


    .umb-forms-mapping-remove.-no-margin-right {
        margin-right: 0;
    }
		`,
  ];
}

export default FormsFieldMapperPropertyUiElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsFieldMapperPropertyUiElement;
    }
}
